// Ana Fidbal API Worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;
    
    // CORS headers
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    // OPTIONS request için CORS
    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: corsHeaders });
    }

    try {
      // Auth endpoints
      if (path.startsWith('/api/auth')) {
        const { handleAuth } = await import('./routes/auth.js');
        const response = await handleAuth(request, env);
        Object.entries(corsHeaders).forEach(([key, value]) => {
          response.headers.set(key, value);
        });
        return response;
      }

      // Sleep endpoints
      if (path.startsWith('/api/sleep')) {
        const { handleSleep } = await import('./routes/sleep.js');
        const response = await handleSleep(request, env);
        Object.entries(corsHeaders).forEach(([key, value]) => {
          response.headers.set(key, value);
        });
        return response;
      }

      // Relaxation endpoints (A/B Test - sadece experiment grubu)
      if (path.startsWith('/api/relaxation')) {
        const { handleRelaxation } = await import('./routes/relaxation.js');
        const response = await handleRelaxation(request, env);
        Object.entries(corsHeaders).forEach(([key, value]) => {
          response.headers.set(key, value);
        });
        return response;
      }

      // Ana sayfa
      return new Response('🌙 Fidbal API Çalışıyor! Backend hazır 🚀', {
        headers: { 'Content-Type': 'text/plain; charset=utf-8', ...corsHeaders }
      });

    } catch (error) {
      return new Response(JSON.stringify({ 
        error: 'Sunucu hatası', 
        message: error.message 
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json', ...corsHeaders }
      });
    }
  }
};